import { SafeAreaView, StyleSheet, Text, View } from 'react-native';
import { ButtonPrimary, ButtonSecondary } from '@/components/primitives/Button';
import { colors, spacing } from '@/design/tokens';
import { textStyles } from '@/design/typography';
import { useAuth } from '@/lib/auth';

// Placeholder role picker — US-032 builds the two large pressables per
// docs/design.md §2.1. For US-031 this screen exists so the (auth) group has
// something to render; the __DEV__ buttons below let testers flip into a tab
// group without the real auth-* edge functions.
export default function AuthIndex() {
  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.content}>
        <Text style={[textStyles.display, styles.title]}>Marketify</Text>
        <Text style={[textStyles.body, styles.subtitle]}>
          Pick your role to continue. The full picker lands in US-032.
        </Text>

        {__DEV__ ? <DevRolePicker /> : null}
      </View>
    </SafeAreaView>
  );
}

// Dev-only role picker. Declared inside an `__DEV__` branch so Metro strips
// the whole component (and the fake token / UUID constants it closes over)
// from production bundles — top-level `const`s would survive dead-code removal.
function DevRolePicker() {
  const { signIn } = useAuth();

  const creatorUser = {
    id: '00000000-0000-0000-0000-000000000001',
    username: 'dev_creator',
    email: null,
    role: 'creator' as const,
    created_at: new Date(0).toISOString(),
    updated_at: new Date(0).toISOString(),
    deleted_at: null,
  };
  const listerUser = {
    id: '00000000-0000-0000-0000-000000000002',
    username: 'dev_lister',
    email: 'dev-lister@example.com',
    role: 'lister' as const,
    created_at: new Date(0).toISOString(),
    updated_at: new Date(0).toISOString(),
    deleted_at: null,
  };

  return (
    <View style={styles.devBlock}>
      <Text style={[textStyles.caption, styles.devCaption]}>DEV ONLY</Text>
      <ButtonPrimary
        label="Sign in as creator"
        onPress={() => signIn('dev-creator-token', creatorUser)}
        accessibilityLabel="Dev sign in as creator"
        testID="dev-signin-creator"
      />
      <View style={styles.spacer} />
      <ButtonSecondary
        label="Sign in as lister"
        onPress={() => signIn('dev-lister-token', listerUser)}
        accessibilityLabel="Dev sign in as lister"
        testID="dev-signin-lister"
      />
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: colors.canvas,
  },
  content: {
    flex: 1,
    alignItems: 'stretch',
    justifyContent: 'center',
    paddingHorizontal: spacing.xl,
    gap: spacing.base,
  },
  title: {
    color: colors.ink,
    textAlign: 'center',
  },
  subtitle: {
    color: colors.ink70,
    textAlign: 'center',
    marginBottom: spacing.xxl,
  },
  devBlock: {
    gap: spacing.sm,
  },
  devCaption: {
    color: colors.ink40,
    textAlign: 'center',
    letterSpacing: 1,
  },
  spacer: {
    height: spacing.md,
  },
});

// Typography — typed text-style presets for the Marketify design system.
// Mirrors docs/design.md §1.3 (font pairing table + line-height rules).
//
// Font substitution: docs/design.md names Clash Display (headings) and Satoshi (body).
// Both are Fontshare-hosted and do not ship with Expo Google Fonts; we use the explicit
// fallbacks listed in §1.3 — Outfit for display/headings, Rubik for body/caption — plus
// JetBrains Mono for monospace. Spec-sanctioned per the same section.
//
// `fontFamily` values are the string keys registered with `expo-font.useFonts` in
// `app/_layout.tsx`. They MUST match the constant names imported from
// `@expo-google-fonts/*` so RN can resolve the loaded assets by name.

import {
  Outfit_600SemiBold,
  Outfit_700Bold,
} from '@expo-google-fonts/outfit';
import {
  Rubik_500Medium,
  Rubik_700Bold,
} from '@expo-google-fonts/rubik';
import { JetBrainsMono_500Medium } from '@expo-google-fonts/jetbrains-mono';
import type { TextStyle } from 'react-native';

export const fontFamilies = {
  displayBold: 'Outfit_700Bold',
  displaySemi: 'Outfit_600SemiBold',
  bodyMedium: 'Rubik_500Medium',
  bodyBold: 'Rubik_700Bold',
  mono: 'JetBrainsMono_500Medium',
} as const;

// Map consumed by `useFonts` — values are the numeric asset handles exported by
// @expo-google-fonts/*, keys are the runtime font-family names.
export const fontAssets = {
  [fontFamilies.displayBold]: Outfit_700Bold,
  [fontFamilies.displaySemi]: Outfit_600SemiBold,
  [fontFamilies.bodyMedium]: Rubik_500Medium,
  [fontFamilies.bodyBold]: Rubik_700Bold,
  [fontFamilies.mono]: JetBrainsMono_500Medium,
} as const;

// Line heights per §1.3: 1.15 for display, ~1.55 for body. Caption + mono tighten
// to 1.4 for dense data rows.
export const textStyles = {
  display: {
    fontFamily: fontFamilies.displayBold,
    fontSize: 28,
    lineHeight: 32,
  },
  h1: {
    fontFamily: fontFamilies.displaySemi,
    fontSize: 22,
    lineHeight: 25,
  },
  h2: {
    fontFamily: fontFamilies.displaySemi,
    fontSize: 20,
    lineHeight: 23,
  },
  body: {
    fontFamily: fontFamilies.bodyMedium,
    fontSize: 15,
    lineHeight: 23,
  },
  caption: {
    fontFamily: fontFamilies.bodyMedium,
    fontSize: 13,
    lineHeight: 18,
  },
  mono: {
    fontFamily: fontFamilies.mono,
    fontSize: 14,
    lineHeight: 20,
  },
  // Micro (pills + chip labels) per §1.3 — Rubik_700Bold stands in for Satoshi 700,
  // 0.08em tracking at 11pt = 0.88pt (RN letterSpacing is absolute points).
  micro: {
    fontFamily: fontFamilies.bodyBold,
    fontSize: 11,
    lineHeight: 14,
    letterSpacing: 0.88,
    textTransform: 'uppercase',
  },
} as const satisfies Record<string, TextStyle>;

export type TextStyleToken = keyof typeof textStyles;
export type FontFamilyToken = keyof typeof fontFamilies;

